final class UniversalLinkRouter {
    static let shared = UniversalLinkRouter()

    private let allowedHosts: Set<String> = ["myapp.com", "www.myapp.com"]

    private init() {}

    @discardableResult
    func handle(url: URL) -> Bool {
        guard let route = parse(url: url) else { return false }
        AppNavigator.shared.route(route)
        return true
    }

    func parse(url: URL) -> UniversalLinkRoute? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }
        guard let host = components.host?.lowercased(), allowedHosts.contains(host) else { return nil }

        let path = components.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")).lowercased()
        guard path == "reset-password" else { return nil }

        let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value ?? ""
        guard !token.isEmpty else { return nil }

        return .resetPassword(token: token)
    }
}

final class AppNavigator {
    static let shared = AppNavigator()

    private weak var navController: UINavigationController?
    private var pendingRoute: UniversalLinkRoute?

    private init() {}

    func bind(navigationController: UINavigationController) {
        self.navController = navigationController
        if let pendingRoute {
            self.pendingRoute = nil
            route(pendingRoute)
